max_ctx = model.config.n_positions
def safe_generate(text, max_new=128):
    ids = tok(text, return_tensors="pt").input_ids
    if ids.shape[1] + max_new > max_ctx:
        raise ValueError(
            f"{ids.shape[1]}+{max_new} exceeds {max_ctx}")
    return model.generate(ids, max_new_tokens=max_new)

def trim(history, enc, max_tokens=6000):
    # keep most recent turns that fit, newest first
    kept, used = [], 0
    for msg in reversed(history):
        n = len(enc.encode(msg["content"]))
        if used + n > max_tokens:
            break
        kept.append(msg); used += n
    return list(reversed(kept))
